import{_ as n,o as t,c as s,a2 as e}from"./chunks/framework.BnBoz4Zl.js";const u=JSON.parse('{"title":"第 25 章 多 Agent 分工、汇总与复核","description":"多 Agent 不是“多开几个聊天窗口”，而是把一个复杂任务拆成边界清楚的角色，让结果可以相互检查，最后仍由一个责任人整合。 简单任务不要强行使用多 Agent。分工和汇总的成本可能高于直接完成。","frontmatter":{},"headers":[],"relativePath":"bluebook/第三篇 进阶篇：把案例变成自己的工作系统/第 25 章 如何进行多 Agent 系统设计/index.md","filePath":"bluebook/第三篇 进阶篇：把案例变成自己的工作系统/第 25 章 如何进行多 Agent 系统设计/index.md","lastUpdated":1784770175000}'),l={name:"bluebook/第三篇 进阶篇：把案例变成自己的工作系统/第 25 章 如何进行多 Agent 系统设计/index.md"};function i(p,a,d,r,o,h){return t(),s("div",null,[...a[0]||(a[0]=[e(`<h1 id="第-25-章-多-agent-分工、汇总与复核" tabindex="-1">第 25 章 多 Agent 分工、汇总与复核 <a class="header-anchor" href="#第-25-章-多-agent-分工、汇总与复核" aria-label="Permalink to &quot;第 25 章 多 Agent 分工、汇总与复核&quot;">​</a></h1><p>多 Agent 不是“多开几个聊天窗口”，而是把一个复杂任务拆成边界清楚的角色，让结果可以相互检查，最后仍由一个责任人整合。</p><h2 id="什么时候值得使用" tabindex="-1">什么时候值得使用 <a class="header-anchor" href="#什么时候值得使用" aria-label="Permalink to &quot;什么时候值得使用&quot;">​</a></h2><ul><li>材料量大，需要并行整理不同类别。</li><li>任务包含事实核验、结构设计、风险检查等不同能力。</li><li>单一 Agent 容易遗漏反向证据或混淆角色。</li><li>中间成果可以单独验收和合并。</li></ul><p>简单任务不要强行使用多 Agent。分工和汇总的成本可能高于直接完成。</p><h2 id="合成场景" tabindex="-1">合成场景 <a class="header-anchor" href="#合成场景" aria-label="Permalink to &quot;合成场景&quot;">​</a></h2><p>为一份虚构的“办公区域改造方案”准备评审材料。所有输入均为合成样本，可拆为五个角色：</p><table tabindex="0"><thead><tr><th>角色</th><th>负责什么</th><th>不负责什么</th></tr></thead><tbody><tr><td>材料整理 Agent</td><td>建目录、识别版本与缺口</td><td>不评价方案</td></tr><tr><td>事实核验 Agent</td><td>核对数字、日期和出处</td><td>不补造缺失事实</td></tr><tr><td>结构 Agent</td><td>组织汇报逻辑和页面大纲</td><td>不改变事实</td></tr><tr><td>风险检查 Agent</td><td>查找假设、矛盾和待确认项</td><td>不确定风险等级</td></tr><tr><td>汇总 Agent</td><td>合并结果、处理重复和冲突</td><td>不替代责任人定稿</td></tr></tbody></table><h2 id="设计步骤" tabindex="-1">设计步骤 <a class="header-anchor" href="#设计步骤" aria-label="Permalink to &quot;设计步骤&quot;">​</a></h2><ol><li>先写总任务目标和最终验收标准。</li><li>按输入或专业边界拆角色，不按“看起来厉害”的职位拆分。</li><li>为每个角色规定输入、输出、禁止动作和完成条件。</li><li>设计共享字段，例如来源编号、事实状态、问题编号和置信状态。</li><li>让角色输出冲突而不是相互覆盖。</li><li>汇总后由责任人确认事实、取舍和最终结论。</li></ol><h3 id="可复制设计模板" tabindex="-1">可复制设计模板 <a class="header-anchor" href="#可复制设计模板" aria-label="Permalink to &quot;可复制设计模板&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>复杂任务：{任务}</span></span>
<span class="line"><span>最终输出：{输出}</span></span>
<span class="line"><span>总体验收：{标准}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请先判断是否真的需要多 Agent。</span></span>
<span class="line"><span>如需要，请为每个角色定义：</span></span>
<span class="line"><span>- 角色目标；</span></span>
<span class="line"><span>- 可读取的输入；</span></span>
<span class="line"><span>- 必须输出的字段；</span></span>
<span class="line"><span>- 禁止动作；</span></span>
<span class="line"><span>- 完成条件；</span></span>
<span class="line"><span>- 与其他角色的交接方式。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>所有角色必须保留来源编号；</span></span>
<span class="line"><span>发现冲突时并列展示，不自行选择；</span></span>
<span class="line"><span>最终汇总前暂停，等待责任人确认。</span></span></code></pre></div><h2 id="人工确认点" tabindex="-1">人工确认点 <a class="header-anchor" href="#人工确认点" aria-label="Permalink to &quot;人工确认点&quot;">​</a></h2><ul><li>分工是否减少复杂度，而不是制造更多交接。</li><li>不同角色是否读取了必要且最小范围的材料。</li><li>冲突、重复和缺口是否完整保留。</li><li>最终结论是否由有权限的责任人确认。</li></ul><h2 id="输出物与验收标准" tabindex="-1">输出物与验收标准 <a class="header-anchor" href="#输出物与验收标准" aria-label="Permalink to &quot;输出物与验收标准&quot;">​</a></h2><ul><li>角色卡、输入输出契约和交接图完整。</li><li>每项事实和问题能追溯到来源与生成角色。</li><li>冲突不会被汇总过程静默删除。</li><li>任一角色失败时，总任务可以停止或局部重试。</li></ul><h2 id="常见弯路与安全边界" tabindex="-1">常见弯路与安全边界 <a class="header-anchor" href="#常见弯路与安全边界" aria-label="Permalink to &quot;常见弯路与安全边界&quot;">​</a></h2><ul><li>角色越多不代表质量越高，优先使用最少角色。</li><li>多个角色重复读全部材料，会扩大权限和成本。按需分配。</li><li>汇总 Agent 不能把不一致结果强行写成一个结论。</li><li>多 Agent 不替代专业责任、审批和人工复核。</li></ul>`,18)])])}const b=n(l,[["render",i]]);export{u as __pageData,b as default};
